import re

def norm_doc(d):
    return re.sub(r"[^a-z0-9]", "", d.casefold())

def blocking_key(rec):
    return f"{(rec.get('apellido_paterno') or '').casefold()}|{(rec.get('region') or '').casefold()}"

def er_score(a, b):
    same_doc = norm_doc(a.get("doc", "")) == norm_doc(b.get("doc", "")) and norm_doc(a.get("doc", "")) != ""
    same_block = blocking_key(a) == blocking_key(b)
    if same_doc and same_block:
        return 1.0
    if same_doc or same_block:
        return 0.5
    return 0.0

a = {"doc": "D-1234", "apellido_paterno": "Quispe", "region": "Lima"}
b = {"doc": "d1234", "apellido_paterno": "Quispe", "region": "Lima"}
c = {"doc": "D-9999", "apellido_paterno": "Quispe", "region": "Lima"}
d = {"doc": "X", "apellido_paterno": "Rojas", "region": "Cusco"}
print(er_score(a, b), er_score(a, c), er_score(a, d))

