def pseudonymize(name):
    return " ".join(f"{t[0]}***" for t in name.split() if t)

print(pseudonymize("Ana Quispe Rojas"))

def case_sheet(er, rel):
    sheet = {
        "entity_resolution_score": er,
        "relationship_signal_score": rel,
    }
    assert "entity_resolution_score" != "relationship_signal_score"
    assert list(sheet.keys())[0] != list(sheet.keys())[1]
    return sheet

